import type { PortalSession, SiaseEndpoint, SiasePage } from '@/types/siase';
export const SIASE_ENDPOINTS: SiaseEndpoint[] = [{ page: 'grades', broker: 'wspd_cgi.sh', path: '/cgi-bin/wspd_cgi.sh/econcfs01.htm' }, { page: 'schedule', broker: 'wspd_cgi.sh', path: '/cgi-bin/wspd_cgi.sh/echalm01.htm' }, { page: 'kardex', broker: 'wspd_cgi.sh', path: '/cgi-bin/wspd_cgi.sh/econkdx01.htm' }, { page: 'personalData', broker: 'wspd_cgi.sh', path: '/cgi-bin/wspd_cgi.sh/edatal01.htm' }, { page: 'enrollmentDates', broker: 'wspd_cgi.sh', path: '/cgi-bin/wspd_cgi.sh/ecohoinsint01.htm' }, { page: 'studentStatus', broker: 'wspd_cgi.sh', path: '/cgi-bin/wspd_cgi.sh/ecSitEst01.htm' }];
export function detectSiasePage(url: URL): SiasePage | null { return SIASE_ENDPOINTS.find((endpoint) => url.pathname.endsWith(endpoint.path))?.page ?? null; }
export function extractPortalSession(url: URL): PortalSession { return { params: Object.fromEntries(url.searchParams.entries()), matricula: url.searchParams.get('HTMLUsuario') ?? undefined }; }
